namespace sv_bd955d47d5f247f48abf1bdf91335484.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with fresh mozzarella, basil, and tomato sauce.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and Pecorino Romano.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
            new(4, "Risotto ai Funghi", "Creamy Arborio rice with mixed wild mushrooms and Parmesan.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato-cream sauce.", 50),
            new(6, "Palak Paneer", "Fresh spinach curry with cubes of soft paneer cheese.", 35),
            new(7, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
            new(8, "Samosa", "Crispy pastry filled with spiced potatoes and peas.", 45),
        },
        [3] = new List<Recipe>
        {
            new(9, "Sushi Rolls", "Vinegared rice with fresh fish and vegetables wrapped in nori.", 40),
            new(10, "Ramen", "Rich pork bone broth with wheat noodles, chashu, and soft-boiled egg.", 55),
            new(11, "Tempura", "Lightly battered and deep-fried shrimp and vegetables.", 25),
            new(12, "Miso Soup", "Traditional dashi broth with tofu, wakame seaweed, and green onion.", 15),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

