@using sv_bd955d47d5f247f48abf1bdf91335484.Models
@using sv_bd955d47d5f247f48abf1bdf91335484.Services
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();
            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        CancelPendingRequest();

        _loadedCuisineId = CuisineId;
        _errorMessage = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Only apply results if this request hasn't been superseded
            if (!cts.Token.IsCancellationRequested)
            {
                _recipes = results;
                _isRefreshing = false;
            }
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (user navigated away or changed cuisine) — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong loading recipes. Please try again.";
        }
    }

    private async Task RetryAsync()
    {
        _errorMessage = null;
        await LoadRecipesAsync();
    }

    private void CancelPendingRequest()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingRequest();
    }
}

